import{_ as e,o as d,c as r,a2 as o}from"./chunks/framework.B72_uj9U.js";const f=JSON.parse('{"title":"Aider — The Benchmark Leaderboard","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/aider/benchmarks.md","filePath":"research/agents/aider/benchmarks.md"}'),i={name:"research/agents/aider/benchmarks.md"};function a(n,t,s,l,h,c){return d(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="aider-—-the-benchmark-leaderboard" tabindex="-1">Aider — The Benchmark Leaderboard <a class="header-anchor" href="#aider-—-the-benchmark-leaderboard" aria-label="Permalink to &quot;Aider — The Benchmark Leaderboard&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Aider maintains the most comprehensive public benchmark for <strong>LLM code-editing performance</strong>. Unlike general coding benchmarks (HumanEval, SWE-bench), Aider&#39;s benchmark tests the full end-to-end pipeline: the LLM must understand the task, write correct code, <strong>and</strong> format its output so the tool can apply edits to files.</p><p>The leaderboard at <a href="https://aider.chat/docs/leaderboards/" target="_blank" rel="noreferrer">aider.chat/docs/leaderboards/</a> is updated regularly and has become a de facto reference for model providers and developers alike.</p><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><h3 id="exercise-set" tabindex="-1">Exercise Set <a class="header-anchor" href="#exercise-set" aria-label="Permalink to &quot;Exercise Set&quot;">​</a></h3><p>The benchmark uses <strong>225 coding exercises</strong> from <a href="https://exercism.org/" target="_blank" rel="noreferrer">Exercism</a>:</p><ul><li>Originally 133 Python exercises from <code>exercism/python</code></li><li>Later expanded to include polyglot exercises</li></ul><p>Each exercise includes:</p><ol><li><strong>Natural language instructions</strong> (markdown)</li><li><strong>Stub code</strong> with function/class skeletons to implement</li><li><strong>Unit tests</strong> that must pass</li></ol><h3 id="the-protocol" tabindex="-1">The Protocol <a class="header-anchor" href="#the-protocol" aria-label="Permalink to &quot;The Protocol&quot;">​</a></h3><p>For each exercise:</p><ol><li><p><strong>First attempt</strong>: Aider sends the LLM:</p><ul><li>The exercise instructions</li><li>The stub implementation file</li><li>System prompt with edit format instructions</li><li>The instruction: &quot;Use the above instructions to modify the supplied files&quot;</li></ul></li><li><p><strong>Apply edits</strong>: Parse the LLM&#39;s response and apply edits to the file</p></li><li><p><strong>Run tests</strong>: Execute the unit test suite</p></li><li><p><strong>Second attempt</strong> (if tests fail): Aider sends:</p><ul><li>The first 50 lines of test error output</li><li>The instruction: &quot;The tests are correct. Fix the code to resolve the errors.&quot;</li></ul></li><li><p><strong>Apply and re-test</strong>: Parse, apply, and test again</p></li><li><p><strong>Score</strong>: Exercise passes if all unit tests pass after either attempt</p></li></ol><h3 id="what-s-being-measured" tabindex="-1">What&#39;s Being Measured <a class="header-anchor" href="#what-s-being-measured" aria-label="Permalink to &quot;What&#39;s Being Measured&quot;">​</a></h3><p>The benchmark measures a <strong>compound skill</strong>:</p><ul><li><strong>Code reasoning</strong> — understanding the problem and writing correct logic</li><li><strong>Edit formatting</strong> — producing output that conforms to the edit format specification</li><li><strong>Error recovery</strong> — diagnosing test failures and producing correct fixes</li></ul><p>A model can fail at any of these steps. Some write correct code but mangle the edit format. Others format perfectly but write buggy code. The benchmark captures both failure modes.</p><h3 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h3><ul><li><strong>Two attempts</strong>: Models get one try, plus one fix attempt with test output. This mirrors real usage (write code, debug based on errors).</li><li><strong>No test source access</strong>: The LLM never sees the unit test source code — only error output from failures. (Though the tests were likely in training data.)</li><li><strong>Temperature 0</strong>: All runs use temperature=0 for reproducibility.</li><li><strong>Cost tracking</strong>: Each run&#39;s total API cost is recorded and reported.</li><li><strong>Edit format variation</strong>: Each model is tested with its optimal edit format (and sometimes multiple formats).</li></ul><h2 id="the-leaderboard-july-2025" tabindex="-1">The Leaderboard (July 2025) <a class="header-anchor" href="#the-leaderboard-july-2025" aria-label="Permalink to &quot;The Leaderboard (July 2025)&quot;">​</a></h2><h3 id="top-tier-75" tabindex="-1">Top Tier (&gt;75%) <a class="header-anchor" href="#top-tier-75" aria-label="Permalink to &quot;Top Tier (&gt;75%)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Cost</th><th>Edit Format</th></tr></thead><tbody><tr><td>GPT-5 (high)</td><td>88.0%</td><td>$29.08</td><td>diff</td></tr><tr><td>GPT-5 (medium)</td><td>86.7%</td><td>$17.69</td><td>diff</td></tr><tr><td>o3-pro (high)</td><td>84.9%</td><td>$146.32</td><td>diff</td></tr><tr><td>Gemini 2.5 Pro Preview 06-05 (32k think)</td><td>83.1%</td><td>$49.88</td><td>diff-fenced</td></tr><tr><td>GPT-5 (low)</td><td>81.3%</td><td>$10.37</td><td>diff</td></tr><tr><td>o3 (high)</td><td>81.3%</td><td>$21.23</td><td>diff</td></tr><tr><td>Grok-4 (high)</td><td>79.6%</td><td>$59.62</td><td>diff</td></tr><tr><td>Gemini 2.5 Pro Preview 06-05 (default think)</td><td>79.1%</td><td>$45.60</td><td>diff-fenced</td></tr><tr><td>o3 (high) + GPT-4.1 (architect)</td><td>78.2%</td><td>$17.55</td><td>architect</td></tr><tr><td>o3</td><td>76.9%</td><td>$13.75</td><td>diff</td></tr><tr><td>Gemini 2.5 Pro Preview 05-06</td><td>76.9%</td><td>$37.41</td><td>diff-fenced</td></tr></tbody></table><h3 id="strong-tier-60-75" tabindex="-1">Strong Tier (60-75%) <a class="header-anchor" href="#strong-tier-60-75" aria-label="Permalink to &quot;Strong Tier (60-75%)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Cost</th><th>Edit Format</th></tr></thead><tbody><tr><td>DeepSeek-V3.2-Exp (Reasoner)</td><td>74.2%</td><td>$1.30</td><td>diff</td></tr><tr><td>Gemini 2.5 Pro Preview 03-25</td><td>72.9%</td><td>—</td><td>diff-fenced</td></tr><tr><td>Claude Opus 4 (32k thinking)</td><td>72.0%</td><td>$65.75</td><td>diff</td></tr><tr><td>o4-mini (high)</td><td>72.0%</td><td>$19.64</td><td>diff</td></tr><tr><td>DeepSeek R1 (0528)</td><td>71.4%</td><td>$4.80</td><td>diff</td></tr><tr><td>Claude Opus 4 (no think)</td><td>70.7%</td><td>$68.63</td><td>diff</td></tr><tr><td>DeepSeek-V3.2-Exp (Chat)</td><td>70.2%</td><td>$0.88</td><td>diff</td></tr><tr><td>Claude 3.7 Sonnet (32k thinking)</td><td>64.9%</td><td>$36.83</td><td>diff</td></tr><tr><td>DeepSeek R1 + Sonnet (architect)</td><td>64.0%</td><td>$13.29</td><td>architect</td></tr><tr><td>o1 (high)</td><td>61.7%</td><td>$186.50</td><td>diff</td></tr><tr><td>Claude Sonnet 4 (32k thinking)</td><td>61.3%</td><td>$26.58</td><td>diff</td></tr><tr><td>Claude 3.7 Sonnet (no thinking)</td><td>60.4%</td><td>$17.72</td><td>diff</td></tr><tr><td>o3-mini (high)</td><td>60.4%</td><td>$18.16</td><td>diff</td></tr></tbody></table><h3 id="mid-tier-45-60" tabindex="-1">Mid Tier (45-60%) <a class="header-anchor" href="#mid-tier-45-60" aria-label="Permalink to &quot;Mid Tier (45-60%)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Cost</th><th>Edit Format</th></tr></thead><tbody><tr><td>Qwen3 235B (no think)</td><td>59.6%</td><td>—</td><td>diff</td></tr><tr><td>Kimi K2</td><td>59.1%</td><td>$1.24</td><td>diff</td></tr><tr><td>DeepSeek R1</td><td>56.9%</td><td>$5.42</td><td>diff</td></tr><tr><td>Claude Sonnet 4 (no thinking)</td><td>56.4%</td><td>$15.82</td><td>diff</td></tr><tr><td>Gemini 2.5 Flash (24k think)</td><td>55.1%</td><td>$8.56</td><td>diff</td></tr><tr><td>DeepSeek V3 (0324)</td><td>55.1%</td><td>$1.12</td><td>diff</td></tr><tr><td>Quasar Alpha</td><td>54.7%</td><td>—</td><td>diff</td></tr><tr><td>o3-mini (medium)</td><td>53.8%</td><td>$8.86</td><td>diff</td></tr><tr><td>Grok 3 Beta</td><td>53.3%</td><td>$11.03</td><td>diff</td></tr><tr><td>Optimus Alpha</td><td>52.9%</td><td>—</td><td>diff</td></tr><tr><td>GPT-4.1</td><td>52.4%</td><td>$9.86</td><td>diff</td></tr><tr><td>Claude 3.5 Sonnet (Oct 2024)</td><td>51.6%</td><td>$14.41</td><td>diff</td></tr><tr><td>Grok 3 Mini Beta (high)</td><td>49.3%</td><td>$0.73</td><td>whole</td></tr><tr><td>DeepSeek Chat V3 (prev)</td><td>48.4%</td><td>$0.34</td><td>diff</td></tr><tr><td>Gemini 2.5 Flash (default)</td><td>47.1%</td><td>$1.85</td><td>diff</td></tr><tr><td>ChatGPT-4o-latest</td><td>45.3%</td><td>$19.74</td><td>diff</td></tr></tbody></table><h3 id="lower-tier-45" tabindex="-1">Lower Tier (&lt;45%) <a class="header-anchor" href="#lower-tier-45" aria-label="Permalink to &quot;Lower Tier (&lt;45%)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Cost</th><th>Edit Format</th></tr></thead><tbody><tr><td>GPT-4.5 Preview</td><td>44.9%</td><td>$183.18</td><td>diff</td></tr><tr><td>Gemini 2.5 Flash (no think)</td><td>44.0%</td><td>$1.14</td><td>diff</td></tr><tr><td>GPT-oss-120b (high)</td><td>41.8%</td><td>$0.74</td><td>diff</td></tr><tr><td>Qwen3 32B</td><td>40.0%</td><td>$0.76</td><td>diff</td></tr><tr><td>Gemini exp-1206</td><td>38.2%</td><td>—</td><td>whole</td></tr><tr><td>Gemini 2.0 Pro</td><td>35.6%</td><td>—</td><td>whole</td></tr><tr><td>Grok 3 Mini Beta (low)</td><td>34.7%</td><td>$0.79</td><td>whole</td></tr><tr><td>o1-mini</td><td>32.9%</td><td>$18.58</td><td>whole</td></tr><tr><td>GPT-4.1 Mini</td><td>32.4%</td><td>$1.99</td><td>diff</td></tr><tr><td>Claude 3.5 Haiku</td><td>28.0%</td><td>$6.06</td><td>diff</td></tr><tr><td>GPT-4o (2024-08-06)</td><td>23.1%</td><td>$7.03</td><td>diff</td></tr><tr><td>GPT-4o-mini</td><td>3.6%</td><td>$0.32</td><td>whole</td></tr></tbody></table><h2 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h2><h3 id="_1-cost-vs-performance-frontier" tabindex="-1">1. Cost vs. Performance Frontier <a class="header-anchor" href="#_1-cost-vs-performance-frontier" aria-label="Permalink to &quot;1. Cost vs. Performance Frontier&quot;">​</a></h3><p>The most interesting dimension is <strong>cost-effectiveness</strong>:</p><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Cost</th><th>$/% point</th></tr></thead><tbody><tr><td>DeepSeek-V3.2-Exp (Chat)</td><td>70.2%</td><td>$0.88</td><td>$0.013</td></tr><tr><td>DeepSeek V3 (0324)</td><td>55.1%</td><td>$1.12</td><td>$0.020</td></tr><tr><td>GPT-5 (low)</td><td>81.3%</td><td>$10.37</td><td>$0.128</td></tr><tr><td>o3-pro (high)</td><td>84.9%</td><td>$146.32</td><td>$1.723</td></tr></tbody></table><p>DeepSeek V3.2 at 70.2% for $0.88 is extraordinarily cost-effective — roughly <strong>170× cheaper per benchmark point</strong> than o3-pro.</p><h3 id="_2-edit-format-matters-enormously" tabindex="-1">2. Edit Format Matters Enormously <a class="header-anchor" href="#_2-edit-format-matters-enormously" aria-label="Permalink to &quot;2. Edit Format Matters Enormously&quot;">​</a></h3><p>The same model can score very differently depending on the edit format:</p><ul><li>Models that default to <code>diff</code> generally score higher than with <code>whole</code> (for capable models)</li><li>Gemini models specifically need <code>diff-fenced</code> — they underperform with standard <code>diff</code></li><li><code>whole</code> format is safest for weaker models but wasteful for strong ones</li></ul><h3 id="_3-thinking-reasoning-tokens-help" tabindex="-1">3. Thinking/Reasoning Tokens Help <a class="header-anchor" href="#_3-thinking-reasoning-tokens-help" aria-label="Permalink to &quot;3. Thinking/Reasoning Tokens Help&quot;">​</a></h3><p>Models with extended thinking consistently outperform their non-thinking variants:</p><ul><li>Claude 3.7 Sonnet: 60.4% (no think) → 64.9% (32k think)</li><li>Claude Opus 4: 70.7% (no think) → 72.0% (32k think)</li><li>Gemini 2.5 Pro: 79.1% (default) → 83.1% (32k think)</li></ul><h3 id="_4-architect-mode-boosts-weaker-models" tabindex="-1">4. Architect Mode Boosts Weaker Models <a class="header-anchor" href="#_4-architect-mode-boosts-weaker-models" aria-label="Permalink to &quot;4. Architect Mode Boosts Weaker Models&quot;">​</a></h3><p>Models that struggle with code editing alone can benefit from architect mode:</p><ul><li>o3 solo: 76.9% → o3 + GPT-4.1 architect: 78.2%</li><li>The benefit is most pronounced for reasoning-focused models</li></ul><h3 id="_5-the-correct-format-rate" tabindex="-1">5. The &quot;Correct Format&quot; Rate <a class="header-anchor" href="#_5-the-correct-format-rate" aria-label="Permalink to &quot;5. The &quot;Correct Format&quot; Rate&quot;">​</a></h3><p>The leaderboard also reports what percentage of exercises had edits that could be <strong>correctly parsed and applied</strong> (regardless of whether the code was correct):</p><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Correct Format</th></tr></thead><tbody><tr><td>GPT-5 (high)</td><td>88.0%</td><td>91.6%</td></tr><tr><td>o3-pro (high)</td><td>84.9%</td><td>97.8%</td></tr><tr><td>Gemini 2.5 Pro (32k)</td><td>83.1%</td><td>99.6%</td></tr><tr><td>DeepSeek V3 (0324)</td><td>55.1%</td><td>99.6%</td></tr></tbody></table><p>Some models (Gemini, DeepSeek) achieve near-perfect format compliance but score lower on actual coding. Others (GPT-5) have slightly lower format compliance but higher coding ability.</p><h2 id="historical-context" tabindex="-1">Historical Context <a class="header-anchor" href="#historical-context" aria-label="Permalink to &quot;Historical Context&quot;">​</a></h2><p>The benchmark has evolved significantly:</p><ol><li><strong>June 2023</strong>: First benchmark — 133 Exercism Python exercises, testing GPT-3.5 vs GPT-4 with whole/diff/function-call formats</li><li><strong>Key finding</strong>: Function-call formats performed worse than plain text (surprised everyone)</li><li><strong>Late 2023</strong>: Added unified diff format to combat GPT-4 Turbo laziness</li><li><strong>Sep 2024</strong>: Architect mode introduced, achieving SOTA with o1-preview + editor pairs</li><li><strong>2025</strong>: Expanded to 225 exercises, became the primary industry leaderboard</li><li><strong>July 2025</strong>: GPT-5 sets new record at 88.0%</li></ol><h2 id="comparison-to-other-benchmarks" tabindex="-1">Comparison to Other Benchmarks <a class="header-anchor" href="#comparison-to-other-benchmarks" aria-label="Permalink to &quot;Comparison to Other Benchmarks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>What it tests</th><th>Aider&#39;s advantage</th></tr></thead><tbody><tr><td>HumanEval</td><td>Standalone function generation</td><td>Aider tests editing existing code</td></tr><tr><td>SWE-bench</td><td>Real GitHub issue resolution</td><td>Aider is lighter-weight, more reproducible</td></tr><tr><td>MBPP</td><td>Simple coding problems</td><td>Aider tests format compliance too</td></tr><tr><td>LiveCodeBench</td><td>Competitive programming</td><td>Aider tests practical code editing</td></tr></tbody></table><p>Aider&#39;s benchmark is uniquely positioned because it tests the <strong>practical workflow</strong>: can the model edit files correctly through a tool interface? This is exactly what matters for AI coding assistants.</p><h2 id="running-the-benchmark" tabindex="-1">Running the Benchmark <a class="header-anchor" href="#running-the-benchmark" aria-label="Permalink to &quot;Running the Benchmark&quot;">​</a></h2><p>The benchmark code is open source in the Aider repository:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Clone and setup</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> clone</span><span style="color:#A6E3A1;"> https://github.com/Aider-AI/aider</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> aider/benchmark</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run against a specific model</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">python</span><span style="color:#A6E3A1;"> benchmark.py</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> gpt-4o</span><span style="color:#A6E3A1;"> --edit-format</span><span style="color:#A6E3A1;"> diff</span></span></code></pre></div><p>Results are deterministic at temperature=0, though OpenAI&#39;s API has some non-determinism (~5-10 response variants for identical requests, likely due to load balancing across model instances).</p>`,56)])])}const m=e(i,[["render",a]]);export{f as __pageData,m as default};
